Here's a TypeScript function to validate email addresses:

```typescript
function isValidEmail(email: string): boolean {
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return emailRegex.test(email);
}
```

This uses a regex pattern that checks for:
- Characters before the @ symbol
- An @ symbol
- Characters after @ but before the dot
- A dot followed by a domain extension

Here's an enhanced version with detailed error messages:

```typescript
interface EmailValidationResult {
  isValid: boolean;
  error?: string;
}

function validateEmail(email: string): EmailValidationResult {
  if (!email) {
    return { isValid: false, error: 'Email address is required' };
  }

  if (email.length > 254) {
    return { isValid: false, error: 'Email address is too long (max 254 characters)' };
  }

  if (!email.includes('@')) {
    return { isValid: false, error: 'Email must contain @ symbol' };
  }

  const [local, domain] = email.split('@');

  if (!local || local.length > 64) {
    return { isValid: false, error: 'Local part is invalid or too long' };
  }

  if (!domain || !domain.includes('.')) {
    return { isValid: false, error: 'Domain must contain a valid TLD' };
  }

  const rfc5322Regex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!rfc5322Regex.test(email)) {
    return { isValid: false, error: 'Email format is invalid' };
  }

  return { isValid: true };
}
```

Here's how to create a simple HTTP server in Node.js:

```typescript
import http from 'http';

const server = http.createServer((req, res) => {
  res.writeHead(200, { 'Content-Type': 'text/plain' });
  res.end('Hello, World!');
});

const PORT = 3000;
server.listen(PORT, () => {
  console.log(`Server running at http://localhost:${PORT}`);
});
```

This creates a basic server that responds with 'Hello, World!' to all requests.
